VALUES
  ('social-worker-moex-06700', 'social-worker', 'social-worker-moex-103-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '下列有關資產累積式脫貧政策（asset-based policy）的敘述，何者比較正確？', '["此說主張社會救助制度應採取所得維持（income maintenance）策略，鼓勵貧困者透過消費，維持生活水準", "在操作上，要先確認誰是值得幫助的人，再用現金補助幫助貧困者回歸主流社會，成為有消費能力的公民", "勤勞所得租稅補貼（Earned Income Tax Credit）是制度核心，是擺脫貧窮文化與相關的心態的工具", "它需要諸如儲蓄誘因（如相對提撥金）、未來資產運用規劃、和放寬低收入戶資格與期限等規定作為配套"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "38e81c1a8908", "answer_pdf_sha1": "aca305e2ad58", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06701', 'social-worker', 'social-worker-moex-103-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '下列有關中華民國建國一百年社會福利政策綱領中，社會救助與津貼的敘述，何者比較正確？', '["政府應建構以社會津貼為主，社會保險為輔，社會救助為最後一道防線的社會安全體系", "社會津貼之設計應以能維持國民之基本經濟生活水準", "社會救助應因應國民特殊需求而設計，針對社會津貼不足處予以補充，逐步整合成國民基本所得保障", "政府應建立失業給付與社會救助體系間的銜接，協助有工作能力者相關就業服務，增進工作能力重返職場"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "38e81c1a8908", "answer_pdf_sha1": "aca305e2ad58", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06702', 'social-worker', 'social-worker-moex-103-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '根據老人福利法規定，提供原住民老人服務及照顧者，應優先遴用原住民或熟諳原住民文化之人，請問 這是那一種福利輸送原則之體現？', '["文化敏感原則", "最佳價值原則", "分散化原則", "無差別歧視原則"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "38e81c1a8908", "answer_pdf_sha1": "aca305e2ad58", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06703', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '愛情是成年前期心理層面發展的主要課題，史登柏格（Sternberg）的愛情三角理論中，指出愛情包含三個 元素，不包括下列那一項？', '["親密", "熱情", "承諾", "信心"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "d2ee28ed3e24", "answer_pdf_sha1": "beeb8e1e0c62", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06704', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列名詞解釋，何者錯誤？', '["同化（assimilation）指將所見所聞的新資訊納入現有基模的認知過程", "適應（adaptation）指個體對環境需求的反應能力", "依附（attachment）指青少年對父母形成強烈的情感連結", "認知（cognition）指從環境及過去經驗當中，運用各種知覺與感覺訊息的過程"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "d2ee28ed3e24", "answer_pdf_sha1": "beeb8e1e0c62", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06705', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列那一項敘述不符合恐懼同志症（homophobia）的表現？', '["對同性戀抱持不符合理智的負面態度", "對性取向抱持開放的態度", "對同性之間性關係的恐懼與仇恨", "具有權威型人格特質者較有可能厭惡同志"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "d2ee28ed3e24", "answer_pdf_sha1": "beeb8e1e0c62", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06706', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', 'Carter & McGoldrick提出的家庭生命週期模式中，身在「有青少年子女的家庭」階段的發展任務為何？', '["家庭界線更有彈性", "接受家庭系統", "接受代間角色的轉換", "系統接納新成員"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "d2ee28ed3e24", "answer_pdf_sha1": "beeb8e1e0c62", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06707', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列那一項不屬於注意力缺陷過動症（ADHD）的診斷標準？', '["活動上經常忽略細節", "輪流過程無法等待", "坐立不安、煩躁", "安靜專注於玩耍"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "d2ee28ed3e24", "answer_pdf_sha1": "beeb8e1e0c62", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06708', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '1 歲半的小美，正是牙牙學語的年紀，當她說出「狗狗、汪汪、怕怕」時，是屬於皮亞傑（Piaget）兒童 語言發展歷程中的那一種語言？', '["情緒式語言", "無意識語言", "電報式語言", "指稱性語言"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "d2ee28ed3e24", "answer_pdf_sha1": "beeb8e1e0c62", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06709', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '美國國家兒童健康及人類發展研究所（NICHD），在1990年曾進行一項兒童照顧的調查，以了解照顧者 與其照顧品質的相關性，以下那一項不符合其研究結果？', '["照顧者採取權威式的管教方式，有較好的照顧品質", "照顧者照顧的孩子愈少，則照顧品質愈好", "最佳的照顧比是：一個照顧者照顧一個孩子", "家中育兒的照顧方式優於托兒中心"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "d2ee28ed3e24", "answer_pdf_sha1": "beeb8e1e0c62", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
